import jakarta.servlet.*;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.*;
import java.io.*;

// Maps this servlet to /login
@WebServlet("/login")
public class LoginServlet extends HttpServlet {

    // ── Lifecycle ──────────────────────────────────────────────────────
    @Override
    public void init(ServletConfig config) throws ServletException {
        super.init(config);
        // Runs ONCE when container first loads this servlet
        System.out.println("LoginServlet initialised");
    }

    // ── GET /login — render login form ────────────────────────────────
    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse res)
            throws ServletException, IOException {

        HttpSession session = req.getSession(false); // don't create session yet
        if (session != null && session.getAttribute("user") != null) {
            res.sendRedirect("/dashboard"); // already logged in
            return;
        }

        res.setContentType("text/html;charset=UTF-8");
        PrintWriter out = res.getWriter();
        out.println("<html><body>");
        out.println("<form method='POST' action='/login'>");
        out.println("  <input name='username' placeholder='Username'>");
        out.println("  <input name='password' type='password' placeholder='Password'>");
        out.println("  <button>Login</button>");
        out.println("</form></body></html>");
    }

    // ── POST /login — process credentials ────────────────────────────
    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse res)
            throws ServletException, IOException {

        String username = req.getParameter("username");  // from form body
        String password = req.getParameter("password");

        // Validate (real app: check DB)
        if ("admin".equals(username) && "secret".equals(password)) {
            // Invalidate any old session (session fixation prevention)
            HttpSession oldSession = req.getSession(false);
            if (oldSession != null) oldSession.invalidate();

            // Create fresh session and store user
            HttpSession session = req.getSession(true);     // create new
            session.setAttribute("user", username);         // server-side
            session.setMaxInactiveInterval(30 * 60);       // 30 min timeout

            res.sendRedirect("/dashboard");  // PRG pattern: redirect after POST
        } else {
            res.setContentType("text/html;charset=UTF-8");
            res.getWriter().println("<p style='color:red'>Invalid credentials</p>");
        }
    }

    // ── Lifecycle ──────────────────────────────────────────────────────
    @Override
    public void destroy() {
        // Runs ONCE on shutdown — close resources opened in init()
        System.out.println("LoginServlet destroyed");
    }
}

// ── Authentication Filter — runs before every protected servlet ───────────
@jakarta.servlet.annotation.WebFilter("/dashboard/*")
class AuthFilter implements Filter {
    @Override
    public void doFilter(ServletRequest req, ServletResponse res, FilterChain chain)
            throws IOException, ServletException {
        HttpServletRequest  httpReq = (HttpServletRequest)  req;
        HttpServletResponse httpRes = (HttpServletResponse) res;

        HttpSession session = httpReq.getSession(false);
        if (session == null || session.getAttribute("user") == null) {
            httpRes.sendRedirect("/login");  // not logged in
            return;
        }
        chain.doFilter(req, res);  // continue to servlet
    }
}

import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.*;
import java.io.*;

@WebServlet("/preferences")
public class PreferencesServlet extends HttpServlet {

    // ── Cookies — stored CLIENT-SIDE ──────────────────────────────────
    // Max 4KB, sent on EVERY matching request, no server memory cost
    // Never store passwords or sensitive data — user can read/edit cookies

    private void setThemeCookie(HttpServletResponse res, String theme) {
        Cookie cookie = new Cookie("theme", theme);
        cookie.setMaxAge(365 * 24 * 3600);  // 1 year expiry
        cookie.setPath("/");                // send on all paths
        cookie.setHttpOnly(true);           // not accessible from JS
        cookie.setSecure(true);             // HTTPS only
        // cookie.setSameSite("Strict");    // CSRF protection (Servlet 6+)
        res.addCookie(cookie);
    }

    private String getThemeCookie(HttpServletRequest req) {
        if (req.getCookies() == null) return "light";
        for (Cookie c : req.getCookies()) {
            if ("theme".equals(c.getName())) return c.getValue();
        }
        return "light"; // default
    }

    // ── Session — stored SERVER-SIDE ──────────────────────────────────
    // Can store any object, only session ID in cookie (JSESSIONID)
    // Consumes server memory — must invalidate on logout!

    private void storeCartInSession(HttpServletRequest req, String item) {
        HttpSession session = req.getSession(); // creates if absent
        @SuppressWarnings("unchecked")
        java.util.List<String> cart =
            (java.util.List<String>) session.getAttribute("cart");
        if (cart == null) {
            cart = new java.util.ArrayList<>();
            session.setAttribute("cart", cart);
        }
        cart.add(item);
        // cart is now in server memory, keyed by JSESSIONID cookie
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse res)
            throws IOException {
        String theme = getThemeCookie(req);
        HttpSession session = req.getSession(false);
        String user = session != null ? (String) session.getAttribute("user") : "guest";

        res.setContentType("text/plain");
        PrintWriter out = res.getWriter();
        out.println("Theme (cookie): " + theme);
        out.println("User  (session): " + user);
        out.println();
        out.println("Cookie characteristics:");
        out.println(" - Max 4KB, stored in browser");
        out.println(" - Sent automatically on every request to matching domain/path");
        out.println(" - Good for: preferences, analytics IDs, remember-me tokens");
        out.println();
        out.println("Session characteristics:");
        out.println(" - Stored server-side (memory or Redis)");
        out.println(" - Only JSESSIONID cookie sent to client");
        out.println(" - Good for: auth state, shopping cart, multi-step forms");
        out.println(" - MUST invalidate on logout: session.invalidate()");
    }

    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse res)
            throws IOException {
        String action = req.getParameter("action");
        if ("setTheme".equals(action)) {
            setThemeCookie(res, req.getParameter("theme"));
        } else if ("addToCart".equals(action)) {
            storeCartInSession(req, req.getParameter("item"));
        } else if ("logout".equals(action)) {
            HttpSession session = req.getSession(false);
            if (session != null) session.invalidate();  // critical!
            // Also clear JSESSIONID cookie
            Cookie jSession = new Cookie("JSESSIONID", "");
            jSession.setMaxAge(0);  // delete cookie
            res.addCookie(jSession);
            res.sendRedirect("/login");
        }
        res.sendRedirect("/preferences"); // PRG
    }
}

problems.description:
Implement and demonstrate the Servlet lifecycle: init → service → destroy.

```java
@WebServlet("/hello")
public class HelloServlet extends HttpServlet {
    private String message;

    @Override
    public void init(ServletConfig config) throws ServletException {
        super.init(config);
        message = config.getInitParameter("greeting"); // from web.xml
        System.out.println("[init] Servlet created once at startup");
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws IOException {
        resp.setContentType("text/html");
        resp.getWriter().println("<h1>" + message + ", " + req.getParameter("name") + "!</h1>");
        System.out.println("[service] Handling request on thread: " + Thread.currentThread().getName());
    }

    @Override
    public void destroy() {
        System.out.println("[destroy] Servlet being unloaded");
    }
}
```

**Lifecycle:**
1. Container calls `init()` once — load resources
2. Container calls `service()` (dispatches to doGet/doPost) — for every request, concurrent threads
3. Container calls `destroy()` once — cleanup

**Key insight:** Servlets are singletons — `init()` and `destroy()` run once. Multiple threads call `service()` concurrently. Never store request state in instance fields.

