problems.solutionCode:
import java.util.concurrent.*;

public class Q2 {

    // UNSAFE: instance field shared across threads
    static class UnsafeServlet {
        private String currentUser; // SHARED — race condition!

        void doGet(String username) throws InterruptedException {
            this.currentUser = username;
            Thread.sleep(50);
            // currentUser may have been overwritten by another thread!
            System.out.println("[UNSAFE] Serving: " + currentUser
                + " (request was for: " + username + ")");
        }
    }

    // SAFE: local variable lives on thread's stack
    static class SafeServlet {
        void doGet(String username) throws InterruptedException {
            String localUser = username; // each thread has its own copy
            Thread.sleep(50);
            System.out.println("[SAFE]   Serving: " + localUser
                + " (request was for: " + username + ")");
        }
    }

    public static void main(String[] args) throws Exception {
        System.out.println("=== UNSAFE Servlet (race condition expected) ===");
        UnsafeServlet unsafe = new UnsafeServlet();
        ExecutorService pool1 = Executors.newFixedThreadPool(3);
        for (String user : new String[]{"Alice", "Bob", "Charlie"}) {
            pool1.submit(() -> { try { unsafe.doGet(user); } catch (Exception e) {} });
        }
        pool1.shutdown();
        pool1.awaitTermination(3, TimeUnit.SECONDS);

        System.out.println();
        System.out.println("=== SAFE Servlet (each thread sees its own user) ===");
        SafeServlet safe = new SafeServlet();
        ExecutorService pool2 = Executors.newFixedThreadPool(3);
        for (String user : new String[]{"Alice", "Bob", "Charlie"}) {
            pool2.submit(() -> { try { safe.doGet(user); } catch (Exception e) {} });
        }
        pool2.shutdown();
        pool2.awaitTermination(3, TimeUnit.SECONDS);

        System.out.println();
        System.out.println("Rule: NEVER store per-request state in servlet instance fields.");
        System.out.println("      Use: local variables, request.setAttribute(), or session.");
    }
}
